// 2D Water Ripples
// The Coding Train / Daniel Shiffman
// https://thecodingtrain.com/CodingChallenges/102-2d-water-ripple.html
// https://youtu.be/BZUdGqeOD0w
// https://editor.p5js.org/codingtrain/sketches/tYXtzNSl

// Algorithm: https://web.archive.org/web/20160418004149/http://freespace.virgin.net/hugo.elias/graphics/x_water.htm

let cols;
let rows;
let current; // = new float[cols][rows];
let previous; // = new float[cols][rows];

let dampening = 0.99;

let x,y;

let ants = []; // empty array to hold ants
let num = 1; //number of ants

function setup() {

  pixelDensity(1);
  createCanvas(400, 400);
  cols = width;
  rows = height;
  // The following line initializes a 2D cols-by-rows array with zeroes
  // in every array cell, and is equivalent to this Processing line:
  // current = new float[cols][rows];
  current = new Array(cols).fill(0).map(n => new Array(rows).fill(0));
  previous = new Array(cols).fill(0).map(n => new Array(rows).fill(0));

    for (i = 0; i < num; i++) {
    ants.push(new Ant());
  }

}

function draw() {

   frameRate(60) //这里也可以控制速度

  background(100);


   for (let ant of ants) {
     ant.display();
     ant.update();
     ant.edge();
  }

  loadPixels();

  previous[x][y] = 1000;
  for (let i = 1; i < cols - 1; i++) {
    for (let j = 1; j < rows - 1; j++) {
      current[i][j] =
        (previous[i - 1][j] +
          previous[i + 1][j] +
          previous[i][j - 1] +
          previous[i][j + 1]) /
          2 -
        current[i][j];
      current[i][j] = current[i][j] * dampening;
      // Unlike in Processing, the pixels array in p5.js has 4 entries
      // for each pixel, so we have to multiply the index by 4 and then
      // set the entries for each color component separately.
      let index = (i + j * cols) * 4;
      pixels[index + 0] = current[i][j]*1;
      pixels[index + 1] = current[i][j]*2;
      pixels[index + 2] = current[i][j]*3;
    }
  }
  updatePixels();

  let temp = previous;
  previous = current;
  current = temp;

}

class Ant {
  // properties
  //https://www.youtube.com/watch?v=mhjuuHl6qHM
  constructor() {
    this.position = createVector(width / 2, height / 2);
    this.velocity = p5.Vector.random2D();
    // this.velocity.setMag(random(1, 2)); //so will explode, it won't be a circle

  }

  display() {
    // stroke(255);
    // strokeWeight(0.5);
    // fill(255);
    // ellipse(this.position.x, this.position.y, 12, 18);
    x=Math.floor(this.position.x);
    y=Math.floor(this.position.y);
  }

  update() {
    this.position.x = this.position.x + random(-5, 5);//这里控制路上改变方向
    this.position.y = this.position.y + random(-1, 1);//这里控制路上改变方向
    this.position.add(this.velocity); //这里控制一条线的速度

  }
    edge() {
    if (this.position.x >= width) {
      this.position.x = 1 ;
    } else if (this.position.x <= 0) {
      this.position.x = width-1;
    }
    if (this.position.y >= height) {
      this.position.y = 1;
    } else if (this.position.y <= 0) {
      this.position.y = height-1;
    }
  }
}

html, body {
  margin: 0;
  padding: 0;
}
canvas {
  display: block;
}

let bg_color;
let elli_color;

function setup() {
  createCanvas(800, 800, WEBGL);
  // bg_color = color(random(255), random(255), random(255));
  elli_color = 0;
  angleMode(DEGREES);
  // normalMaterial();
}

function draw() {
  bg_color = color(random(255), random(255), random(255));
  background(bg_color);

  let mx = mouseX - width / 2;
  let my = mouseY - height / 2;


  if (mouseY > 400) {
    background(0);

    elli_color = color(random(255), random(255), random(255));

    translate(mx, my);

    // beginShape();
    strokeWeight(10);
    stroke(random(255));
    fill(elli_color);
    ellipse(0, 0, random(10, 150));

    textAlign(CENTER, CENTER);
    textSize(random(20, 80));
    // fill(elli_color);
    text("hello world", 0, 0);
    // endShape();

  } 

  else {
    background(bg_color);

    // Sphere
    push();
    translate(mx, my);
    rotateWithFrameCount();
    stroke(0);
    strokeWeight(2);
    sphere(random(30, 100));
    pop();

  }
}

function rotateWithFrameCount() {
  rotateZ(frameCount);
  rotateX(frameCount);
  rotateY(frameCount);
}

html, body {
  margin: 0;
  padding: 0;
}
canvas {
  display: block;
}

let particles = [];
let num = 1000;
let nx, ny;
let released = false;
let i;
let count = 0;
let inc = 0;
let dia = [10, 30, 50, 70, 90];
let xx = 0;
let yy = 0;
let posX = 300;
let posY = 300;
let sound;

function setup() {
  createCanvas(600, 600);
  for (let i = 0; i < num; i++) {
    particles.push(createVector(random(width), random(height)));
  }
}

function draw() {
  background(0, 10);

  nx = random(0, width);
  ny = random(0, height);
  circle(nx, ny, 5);

  strokeWeight(2.5);
  circle(mouseX, mouseY, 5);

  // credit to Easy Perlin Noise Flow Fields by Barney Codes [https://www.youtube.com/watch?v=sZBfLgfsvSk]
  // Perlin noise is smooth and continuous (and repeatable), meaning that it doesn't exhibit sudden changes. This property makes it ideal for generating realistic, organic-looking textures.
  // I applied the noise function to create an organic feel is what I have found of value to build upon in your project, and I utilized the two dimension noise (picked in align with p.x and p.y, similar to vertex) to subtly shift the positions of the fish particles in each frame, creating such a flow field. 

  for (let i = 0; i < num; i++) {
    let p = particles[i];
    point(p.x, p.y);
    let n = noise(p.x * 0.006, p.y * 0.006);
    let a = 2 * PI * n * map(mouseX, 0, width, 1, 2);
    p.x += cos(a);
    p.y += sin(a);

    //I correlated the color with the direction of the fish’s movement, controlled by sin(a) and cos(a), and incorprate user interaction through mapping the value of mouseX.

    let r = map(sin(a), -1, 1, 0, 255);
    let b = map(cos(a), -1, 1, 0, 255);
    let g = 100;
    stroke(r, g, b);

    if (!onScreen(p)) {
      p.x = random(width);
      p.y = random(height);
    }

    let d = dist(p.x, p.y, xx, yy);
    let d2 = dist(p.x, p.y, mouseX, mouseY);

    if (d <= 40) {
      p.x = random(width);
      p.y = random(height);
    }

    if (d > 40 && d < 80) {
      let dx = p.x - xx;
      let dy = p.y - yy;
      let xfish = dx * 0.05;
      let yfish = dy * 0.05;
      p.x += xfish;
      p.y += yfish;
    }
    if (mouseIsPressed) {
      if (d2<40) {
        let dx = p.x - xx;
        let dy = p.y - yy;
        let xfish = dx * 0.05;
        let yfish = dy * 0.05;
        p.x += xfish;
        p.y += yfish;
      }
    }
  }

  // ripple();
  predator();

  noStroke()
  fill(255);
  text("try to move / press you mouse", 10, 30);
}

function onScreen(v) {
  return v.x >= 0 && v.x <= width && v.y >= 0 && v.y <= height;
}

function ripple() {
  if (mouseIsPressed) {
    for (let i = 0; i < dia.length; i++) {
      stroke(255, 25);
      noFill();
      circle(mouseX, mouseY, dia[i]);
      dia[i] += 1;
      if (dia[i] >= 70) {
        dia[i] = 10;
      }
    }
  }
}

  // credit to Coding Challenge #36: Blobby! by The Coding Train [https://www.youtube.com/watch?v=rX5p-QRP6R4&list=PLRqwX-V7Uu6ZiZxtDDRCi6uhfTH4FilpH&index=44]
  // I specified a series of the vertex coordinates that construct the circle shape of predator by connecting them. I added noise fuction to their coordinates to produce the effect of blurring the edges.

function predator() {
  if (mouseIsPressed) {
    let targetX = mouseX;
    let targetY = mouseY;

    let disX = targetX - xx;
    let disY = targetY - yy;

    xx += disX * 0.02;
    yy += disY * 0.02;

    posX = xx;
    posY = yy;
  } else {
    let xspd = map(noise(inc), 0, 1, -2, 2);
    let yspd = map(noise(1000 + inc), 0, 1, -2, 2);
    xx = posX + xspd;
    yy = posY + yspd;

    posX = xx;
    posY = yy;

    posX = constrain(posX, 0, width);
    posY = constrain(posY, 0, height);
  }

  push();
  translate(xx, yy);
  noStroke();
  fill(160, 130, 170, 20);
  beginShape();
  for (var a = 0; a < TWO_PI; a += 0.1) {
    let xoff = cos(a) + 1;
    let yoff = sin(a) + 1;
    let scl1 = map(sin(inc), -1, 1, 20, 30);
    let scl2 = map(sin(inc), -1, 1, 40, 50);
    let r = map(noise(xoff + inc, yoff + inc), 0, 1, scl1, scl2);
    let x = r * cos(a);
    let y = r * sin(a);
    vertex(x, y);
  }
  endShape(CLOSE);
  inc += 0.01;
  pop();
}

html, body {
  margin: 0;
  padding: 0;
}
canvas {
  display: block;
}

//transition
let sceneControl = 0;
let scene1Time;
let scene2Time;
let mouseclick = 0;
//sketch1
let gearRadius = [];
let gearX = [];
let gearY = [];
let gearTeeth = [];
let gearToothDepth = [20];
let gearClicked = [];
let gearRotateangle = [];
let coin = [];
let coinSlotDist;
let fillOpa = 255;
let strokeOpa = 255;
let a = [];
let gearNum;
let overlapping;

let ballBoolean = [];
let lerpBool = 0;
let ballX = [];
let ballY = [];

//sketch2
let petalsPerLayer = 6;
let layers = [];
let maxLayers = 10;
let firstScale = 0.4;
let scaleIncrement = 0.15;
let firstLayerGrowthSpeed = 0.05;
let baseGrowthSpeed = 0.02;
let layerAddInterval = 30;
let baseRotationSpeed = 0.5; // 基础旋转速度
let isFullyGrown = false;
let shouldRotate = false;

//sketch3
let i;
let count = 0;
let inc = 0;
let dia = [10, 30, 50, 70, 90];

let centerX = 400;
let centerY = 250;
let m = [];
let n = [];
let mSpd = [];
let nSpd = [];
let diam = [];
let fruitOpa = 1;
let boom = false;
let fruitScale = 0;

function preload() {
  coinsound = loadSound("coin.wav");
  // music = loadSound("Joep Beving - Paris senflamme (1).mp3")
}
function setup() {
  createCanvas(800, 500);
  colorMode(HSB);
  angleMode(DEGREES);
  gearNum = 6;
  let attempts = 0;
  while (gearX.length < gearNum && attempts < 100) {
    overlapping = false;
    let newGearX = random(325, 700);
    let newGearY = random(100, 500);
    let newGearTeeth = random([12, 14, 16, 18]);
    let newGearRadius = random(75, 150);

    for (let j = 0; j < gearX.length; j++) {
      let d = dist(newGearX, newGearY, gearX[j], gearY[j]) + 50;
      if (d < newGearRadius + gearRadius[j]) {
        overlapping = true;
        break;
      }
    }
    if (!overlapping) {
      gearX.push(newGearX);
      gearY.push(newGearY);
      gearTeeth.push(newGearTeeth);
      gearRadius.push(newGearRadius);
      gearRotateangle.push(0);
      gearClicked.push(false);
    }
    attempts++;
  }

  gearNum = gearX.length;

  for (let i = 0; i < gearNum; i++) {
    ballBoolean.push(0);
  }
  for (let i = 0; i < gearNum; i++) {
    ballX.push(-50);
    ballY.push(-50);
  }

  for (let i = 0; i < 3000; i++) {
    m[i] = width / 2;
    n[i] = height / 2;
    mSpd[i] = random(-1.5, 1.5);
    nSpd[i] = random(-1.7, 1.7);
    diam[i] = random(5, 50);
  }
}

function draw() {
  background(0, 0, 0);
  // music.play()
  if (sceneControl == 0 || sceneControl == 1) {
    drawScene1();
    if (sceneControl == 1) {
      background(0, 0, 0, (frameCount - scene1Time) / 50);
      fill(255);
      noStroke();
      circle(400, 250, 10);
      if (frameCount >= scene1Time + 50) {
        sceneControl = 2;
      }
    }
  } else if (sceneControl == 2 || sceneControl == 2.5) {
    textAlign(CENTER);
    textSize(20);
    textFont("Lucida Grande");
    text("I bloom here.", 400, 475);
    push();
    translate(400, 250);
    fill(255);
    circle(0, 0, 10);
    for (let w = 0; w < 60; w++) {
      noFill();
      stroke(255, sin(w * 6 + (frameCount % 360)) / 9);
      circle(0, 0, 200 - sin(w) * 200);
    }

    if (!isFullyGrown && mouseIsPressed) {
      growAndRotateFlower();
      shouldRotate = true;
      scene2Time = frameCount;
    } else if (isFullyGrown && !mouseIsPressed) {
      rotateFlower();
      sceneControl = 2.5;
    } else {
      scene2Time = frameCount;
      rotateFlower();
    }

    drawCurrentFlowerState();

    pop();

    if (sceneControl == 2.5 && frameCount - scene2Time < 50) {
      background(0, 0, 0, (frameCount - scene2Time) / 50);
      mouseclick = 0;
    } else if (sceneControl == 2.5) {
      background(0);
      sceneControl = 3;
      drawScene3();
    }
  } else if (sceneControl == 3) {
    drawScene3();
  }
}

function drawScene1() {
  fill(197, 0, 90);
  //noStroke();
  rect(75, 100, 10, 100);
  strokeWeight(2);
  stroke(255);
  //noStroke();
  line(150, 0, 150, 500);
  noStroke();
  for (let n = 0; n < gearX.length; n++) {
    push();
    translate(gearX[n], gearY[n]);
    rotate(frameCount * gearRotateangle[n]);
    let angleStep = 360 / gearTeeth[n];
    fill(197, 12, 100, 0.4);
    beginShape();
    //noStroke();
    for (let i = 0; i < 360; i += angleStep) {
      let angle3 = i;
      let angle4 = i + angleStep / 2;
      let x1 = cos(angle3) * (gearRadius[n] + gearToothDepth[0]);
      let y1 = sin(angle3) * (gearRadius[n] + gearToothDepth[0]);
      let x2 = cos(angle4) * gearRadius[n];
      let y2 = sin(angle4) * gearRadius[n];
      vertex(x1, y1);
      vertex(x2, y2);
    }
    endShape(CLOSE);
    // stroke(0)
    // strokeWeight(2);
    fill(197, 20, 100, 0.15);
    //noFill()

    ellipse(0, 0, gearRadius[n], gearRadius[n]);
    pop();
  }

  coinSlotDist = dist(mouseX, mouseY, 100, 100);
  drawCoin(mouseX, mouseY, fillOpa, strokeOpa);

  for (let i = 0; i < gearNum; i++) {
    if (ballBoolean[i] != 0 && lerpBool < gearNum) {
      ballX[i] = gearX[i];
      ballY[i] = gearY[i];
      if (ballBoolean[i] == 1) {
        lerpBool += ballBoolean[i];
        ballBoolean[i] += 1;
      }
    }

    if (lerpBool == gearNum) {
      ballX[i] = lerp(ballX[i], width / 2, 0.05);
      ballY[i] = lerp(ballY[i], height / 2, 0.05);
      sceneControl = 1;
      if (dist(ballX[i], ballY[i], width / 2, height / 2) > 1) {
        sceneControl = 0;
        scene1Time = frameCount;
      }
    }

    ball(ballX[i], ballY[i]);
  }
  textAlign(CENTER);
  textSize(20);
  textFont("Lucida Grande");
  text("I sprout from here.", 400, 475);
}

function mouseClicked() {
  if (coinSlotDist < 100 && gearRotateangle[0] == 0) {
    fillOpa = 0;
    strokeOpa = 0;
    coinsound.play();
    for (let i = 0; i < gearNum; i++) {
      gearRotateangle[i] = random(0.5, 1);
    }
  }
  for (let i = 0; i < gearNum; i++) {
    let distance = dist(mouseX, mouseY, gearX[i], gearY[i]);
    if (distance < 100 && gearRotateangle[0]) {
      ballBoolean[i] = 1;
    }
  }
  mouseclick += 1;
}

function ball(x, y) {
  push();
  circle(x, y, 10);
  pop();
}

function drawCoin(x, y, fillOpa, strokeOpa) {
  push();
  translate(x, y);
  stroke(0, strokeOpa);
  noStroke();
  fill(197, 0, 90, fillOpa);
  circle(0, 0, 50);
  textAlign(CENTER);
  textFont("Arial");
  strokeWeight(0.2);
  textSize(50);
  fill(0, fillOpa);
  text("S", 0, 20);
  textSize(60);
  text("l", 0, 22);
  pop();
}

function growAndRotateFlower() {
  if (frameCount % layerAddInterval == 0 && layers.length < maxLayers) {
    let s = firstScale + scaleIncrement * layers.length;
    let newLayer = {
      s: s,
      currentScale: 0,
      petalChange: random(360 / petalsPerLayer),
      rotation: 0,
    };
    layers.push(newLayer);
  }

  let isStillGrowing = false;

  for (let i = layers.length - 1; i >= 0; i -= 1) {
    let layer = layers[i];
    if (i === 0) {
      growthSpeed = firstLayerGrowthSpeed;
    } else {
      growthSpeed = baseGrowthSpeed;
    }
    if (layer.currentScale < layer.s - 0.1) {
      layer.currentScale += (layer.s - layer.currentScale) * growthSpeed;
      isStillGrowing = true;
    }

    rotateLayer(layer, i);
  }
  if (!isStillGrowing && layers.length === maxLayers) {
    isFullyGrown = true;
  }
}

function rotateFlower() {
  for (let i = layers.length - 1; i >= 0; i -= 1) {
    let layer = layers[i];
    rotateLayer(layer, i);
  }
}

function rotateLayer(layer, index) {
  let rotationSpeed =
    (baseRotationSpeed * (layers.length - index)) / (index + 1);
  layer.rotation += rotationSpeed;
}

function drawCurrentFlowerState() {
  for (let i = 0; i < layers.length; i++) {
    let layer = layers[i];
    drawLayer(layer.currentScale, layer.petalChange, layer.rotation);
  }
}

function drawLayer(s, layerPetalChange, layerRotation) {
  push();
  rotate(layerRotation);
  for (let n = 0; n < 360; n += 360 / petalsPerLayer) {
    push();
    rotate(n + layerPetalChange);
    drawPetal(s);
    pop();
  }
  pop();
}

function drawPetal(s) {
  push();
  scale(s);
  strokeWeight(2);
  fill(197, 20, 100, 0.15);
  beginShape();
  vertex(0, 0);
  vertex(-40, -50);
  vertex(-55, -100);
  vertex(-40, -125);
  vertex(-10, -140);
  vertex(0, -130);
  vertex(10, -140);
  vertex(40, -125);
  vertex(55, -100);
  vertex(40, -50);
  vertex(0, 0);
  endShape();
  pop();
}

function drawScene3() {
  textAlign(CENTER);
  textSize(20);
  fill(255);
  textFont("Lucida Grande");
  text("I return to here.", 400, 475);
  push();
  translate(400, 250);
  noStroke();
  fill(197, 20, 100, fruitOpa);
  if (fruitScale < 1) {
    fruitScale += 0.01;
  }
  scale(fruitScale);
  beginShape();
  for (var a = 0; a < 360; a += 0.1) {
    let xoff = cos(a) + 1;
    let yoff = sin(a) + 1;
    let scl1 = map(sin(inc), -1, 1, 20, 30);
    let scl2 = map(sin(inc), -1, 1, 40, 50);
    let r = map(noise(xoff + inc, yoff + inc), 0, 1, scl1, scl2);
    let x = r * cos(a);
    let y = r * sin(a);

    vertex(x, y);
  }
  endShape(CLOSE);

  inc += 0.01;
  pop();
  if (mouseclick >= 1) {
    boom = true;
  }
  if (boom) {
    sceneControl = 0;
    for (let i = 0; i < 300; i++) {
      m[i] += mSpd[i] * 10;
      n[i] += nSpd[i] * 10;
      fill(random(359), random(50, 100), random(50, 100));
      noStroke();
      circle(m[i], n[i], diam[i]);
      fruitOpa -= 0.05;
      if (
        0 < m[i] + diam[i] / 2 &&
        m[i] - diam[i] / 2 < width &&
        0 < n[i] + diam[i] / 2 &&
        n[i] - diam[i] / 2 < height
      ) {
        sceneControl = 3;
      }
    }
    if (sceneControl == 0) {
      clearReset();
    }
  }
}
//transition
function clearReset() {
  sceneControl = 0;

  mouseclick = 0;
  //sketch1
  gearRadius = [];
  gearX = [];
  gearY = [];
  gearTeeth = [];
  gearToothDepth = [20];
  gearClicked = [];
  gearRotateangle = [];
  coin = [];

  fillOpa = 255;
  strokeOpa = 255;
  a = [];

  ballBoolean = [];
  lerpBool = 0;
  ballX = [];
  ballY = [];

  //sketch2
  petalsPerLayer = 6;
  layers = [];
  maxLayers = 10;
  firstScale = 0.4;
  scaleIncrement = 0.15;
  firstLayerGrowthSpeed = 0.05;
  baseGrowthSpeed = 0.02;
  layerAddInterval = 30;
  baseRotationSpeed = 0.5; // 基础旋转速度
  isFullyGrown = false;
  shouldRotate = false;

  //sketch3

  count = 0;
  inc = 0;
  dia = [10, 30, 50, 70, 90];

  centerX = 400;
  centerY = 250;
  m = [];
  n = [];
  mSpd = [];
  nSpd = [];
  diam = [];
  fruitOpa = 1;
  boom = false;
  fruitScale = 0;
  gearNum = 6;
  attempts = 0;
  while (gearX.length < gearNum && attempts < 100) {
    overlapping = false;
    newGearX = random(325, 700);
    newGearY = random(100, 500);
    newGearTeeth = random([12, 14, 16, 18]);
    newGearRadius = random(75, 150);

    for (let j = 0; j < gearX.length; j++) {
      d = dist(newGearX, newGearY, gearX[j], gearY[j]) + 50;
      if (d < newGearRadius + gearRadius[j]) {
        overlapping = true;
        break;
      }
    }
    if (!overlapping) {
      gearX.push(newGearX);
      gearY.push(newGearY);
      gearTeeth.push(newGearTeeth);
      gearRadius.push(newGearRadius);
      gearRotateangle.push(0);
      gearClicked.push(false);
    }
    attempts++;
  }

