    if(m[i]>width){
      mSpd[i] = -mSpd[i]
    }
    if (n[i]<0){
      nSpd[i]= -nSpd[i]
    }
    if(n[i]>height){
      nSpd[i]=-nSpd[i]
    }
  }
}

