class Particle {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.size = random(10, 30);
    this.speedY = random(1, 4);
    this.alpha = 255;
  }

  update() {
    this.y -= this.speedY;
    this.alpha -= 2;
  }

  display() {
    fill(150, this.alpha);
    ellipse(this.x, this.y, this.size);
  }

  isFinished() {
    return this.alpha <= 0;
  }
}

