// You only code inside this class.
// Start by giving the dancer your name, e.g. LeonDancer.
class ArialDancer{
  constructor(startX, startY){
    this.x = startX;
    this.y = startY;
    this.angel = 0;
    this.rota = 1;
    this.eye=3
    this.blink = 0.4
    this.decoAngle = 0
    this.tag1 = 0

  }
  update(){
    if (this.angel >= 0 || this.angel <= -0.15) {
      this.rota *= -1;
    }
    this.angel += 0.0017 * this.rota;

    if (frameCount % 15 == 0 && 4>=this.tag1 >2){
      this.tag1 += sin(frameCount/200)
    }
    else{
      this.tag1 -= sin(frameCount/200)
    }

    this.eye -= this.blink
    if (this.eye > 8 || this.eye<2){
      this.blink = -this.blink
    }

    this.decoAngle += radians(1);

  }
  display(){
    // the push and pop, along with the translate 
    // places your whole dancer object at this.x and this.y.
    // you may change its position on line 19 to see the effect.
    push();
    rotate(this.angel);
    translate(this.x, this.y);

    //wind chimes 1    
    textSize(100)
    text('🎐', 0,0)

    ////wind chimes 2
    stroke("#99cc00")
    strokeWeight(3)
    line(30,-21,30,60)
    noFill()
    circle(30, -25, 8)
    //the cloud
    noStroke()
    fill("#ccff99")
    circle(20,17,47)
    circle(28,2,36)
    circle(50,17,36)
    //decoration
    push()
    translate(30,47)
    fill("#ff3300")
    rectMode(CENTER)
    rotate(this.decoAngle)
    rect(0,0,9,9)
    pop()
    //tag
    push()
    fill(204,204,204)
    translate(30,60)
    rotate(this.tag1)
    beginShape()
    vertex(-10,-5)
    vertex(10,-5)
    vertex(20,25)
    vertex(0,25)
    endShape()
    //letters on the tag
    fill(255,0,0)
    textSize(7)
    text("❤",-1,5)
    text("❤",2,12)
    text("❤",5,20)
    pop()
    //eye
    fill(0)
    ellipse(8,15,6,this.eye)
    ellipse(20,15,6,this.eye)


    this.drawReferenceShapes()



    pop();
  }  
  drawReferenceShapes(){
    noFill();
    stroke(255, 0, 0);
    line(-5, 0, 5, 0);
    line(0, -5, 0, 5);
    stroke(255);                       
    rect(-100, -100, 200, 200);    
    fill(255);
    stroke(0);
  }


}





