  beginShape();

  for (let i = 0; i < coordinateNum; i++) {
    curveVertex(
      r *
        noise(frameCount * freqDM + randomArray[i]) *
        cos((2 * PI * i) / coordinateNum),
      r *
        noise(frameCount * freqDM + randomArray[i]) *
        sin((2 * PI * i) / coordinateNum)
    );
  }

  endShape(CLOSE);
  pop();
}
