function symmetrical_eye(a, b, c) {
  circle(-a, -b, c);
  circle(a, -b, c);
}

function eyeWhite(a, b, c) {
  fill(255);
  noStroke();
  circle(-a, -b, c);
  circle(a, -b, c);
}

function eyeBlackFollowMouse(a, b, whiteSize, blackSize) {
  //distance between translate and my mouse
  let mx = mouseX - width / 2;
  let my = mouseY - height / 2;

  //the max distance the blackeye could move within the white eye
  let maxR = whiteSize / 2 - blackSize / 2 - 2;

  //position of the blackeye
  let lx = -a;
  let ly = -b;

  //the vector between my mouse and black eye
  let vectorXL = mx - lx;
  let vectorYL = my - ly;

  //move only inside the white range
  let distL =  dist(mx, my, lx, ly);
  if (distL > maxR) {
    vectorXL = (vectorXL / distL) * maxR;
    vectorYL = (vectorYL / distL) * maxR;
  }

  //right eye
  let rx = a;
  let ry = -b;
  let vectorXR = mx - rx;
  let vectorYR = my - ry;
  let distR = dist(mx, my, rx, ry);
  if (distR > maxR) {
    vectorXR = (vectorXR / distR) * maxR;
    vectorYR = (vectorYR / distR) * maxR;
  }

  //black eye
  fill(0);
  noStroke();
  circle(lx + vectorXL, ly + vectorYL, blackSize);
  circle(rx + vectorXR, ry + vectorYR, blackSize);
}

function symmetrical_leg(x1, y1, x2, y2, x3, y3, x4, y4) {
  //bottom left
  beginShape();
  curveVertex(x1, y1);
  curveVertex(x1, y1);
  curveVertex(x2, y2);
  curveVertex(x3, y3);
  curveVertex(x4, y4);
  curveVertex(x4, y4);
  endShape();

  //bottom right
  beginShape();
  curveVertex(-x1, y1);
  curveVertex(-x1, y1);
  curveVertex(-x2, y2);
  curveVertex(-x3, y3);
  curveVertex(-x4, y4);
  curveVertex(-x4, y4);
  endShape();
}

function symmetrical_feet(a1, b1, c1, a2, b2, a3, b3, a4, b4, c, w) {
  //bottom left
  fill(r, g, b);
  noStroke();
  circle(a1, b1, c1);
  strokeWeight(w);
  stroke(r, g, b);
  line(a1, b1, a2, b2);
  line(a1, b1, a3, b3);
  line(a1, b1, a4, b4);
  circle(a2, b2, c);
  circle(a3, b3, c);
  circle(a4, b4, c);

  //bottom right
  fill(r, g, b);
  noStroke();
  circle(-a1, b1, c1);
  strokeWeight(w);
  stroke(r, g, b);
  line(-a1, b1, -a2, b2);
  line(-a1, b1, -a3, b3);
  line(-a1, b1, -a4, b4);
  circle(-a2, b2, c);
  circle(-a3, b3, c);
  circle(-a4, b4, c);
}

