      stroke(randomColor);
      triangle(-40, -41, -50, -65, -30, -53);
      triangle(40, -41, 50, -65, 30, -53);
    }
  } else {
    fill(0, 153, 51);
    stroke(0, 153, 51);
    triangle(-40, -41, -50, -65, -30, -53);
    triangle(40, -41, 50, -65, 30, -53);
  }
  if(stage<2){
  fill(242, 242, 242, 150);
  stroke(255, 80);
  } else if(stage==2){
  lerpedColor = lerpColor(startColor, endColor, map(x, x31, 700, 0, 1));
  fill(lerpedColor);
  stroke(lerpedColor);
  } else{
  fill(153, 204, 0, 120);
  stroke(153, 204, 0, 80);
  }
  ellipse(0, 0, 100, 130); //body(transparent)
  fill(0, 153, 51);
  stroke(0, 153, 51);
  ellipse(0, - 10, 44, 58); //eye(green)
  fill(252, 233, 29);
  beginShape();
  vertex(0, - 35);
  vertex(- 12, - 10);
  vertex(0, 15);
  vertex(12, - 10);
  endShape(CLOSE);
  pop();
}

