function drawSingleFlower(x, y) {//one
  push();
  translate(x, y);
  scale(0.4);
  push(); //green leaves1
  rotate(PI / 4);
  for (let j = 0; j < 4; j++) {
    stroke(153, 204, 0);
    fill(153, 204, 0);
    beginShape();
    curveVertex(-10, -40);
    curveVertex(-10, -40);
    curveVertex(0, -70);
    curveVertex(10, -40);
    curveVertex(0, 0);
    curveVertex(0, 0);
    endShape(CLOSE);
    rotate(PI / 2);
  }
  pop(); //end of green leaves 1

  for (let k = 0; k < 8; k++) {
    stroke(0, 153, 51);
    fill(0, 153, 51);
    beginShape();
    curveVertex(-12, -35);
    curveVertex(-12, -35);
    curveVertex(0, -60);
    curveVertex(12, -35);
    curveVertex(0, 0);
    curveVertex(0, 0);
    endShape(CLOSE);
    rotate(PI / 3);
  } //green leaves 2

  push();
  rotate(PI / 8);
  for (let l = 0; l < 8; l++) {
    stroke(252, 233, 29);
    fill(252, 233, 29);
    beginShape();
    curveVertex(-8, -24);
    curveVertex(-8, -24);
    curveVertex(0, -40);
    curveVertex(8, -24);
    curveVertex(0, 0);
    curveVertex(0, 0);
    endShape(CLOSE);
    rotate(PI / 4);
  }
  pop(); //yellow petal

  for (let m = 0; m < 8; m++) {
    stroke(255);
    fill(255);
    beginShape();
    curveVertex(-8, -24);
    curveVertex(-8, -24);
    curveVertex(0, -40);
    curveVertex(8, -24);
    curveVertex(0, 0);
    curveVertex(0, 0);
    endShape(CLOSE);
    rotate(PI / 4);
  }
  pop();
}

