function drawLily(xl,yl){
  strokeWeight(1);
  stroke(0, 153, 51);
  fill(0, 153, 51);
  push(); //outer
  translate(xl,yl);
  push(); //inner
  rotate((PI / 6) * -1);
  beginShape();
  curveVertex(0, 0);
  curveVertex(0, 0);
  curveVertex(-8, -25);
  curveVertex(-0, -60);
  curveVertex(8, -25);
  curveVertex(0, 0);
  curveVertex(0, 0);
  endShape();
  rotate(PI / 3);
  beginShape();
  curveVertex(0, 0);
  curveVertex(0, 0);
  curveVertex(-10, -30);
  curveVertex(-0, -70);
  curveVertex(10, -30);
  curveVertex(0, 0);
  curveVertex(0, 0);
  endShape();
  pop(); //end of inner
  noFill();
  strokeWeight(2);
  beginShape();
  curveVertex(0,0);
  curveVertex(0, 0);
  curveVertex(- 2, -30);
  curveVertex(- 8, -65);
  curveVertex(- 25, -80);
  curveVertex(- 50, -85);
  curveVertex(- 50, -85);
  endShape();
  for (i = 0; i < 2; i++) {
    fill(255, 220);
    stroke(255, 120);
    rect(- 60 + i * 24, -85 + i * 5, 15, 17, 5);
    circle(- 60 + i * 24, -67 + i * 5, 5);
    circle(- 53 + i * 24, -67 + i * 5, 5);
    circle(- 46 + i * 24, -67 + i * 5, 5);
  }
  pop(); //out
}

function drawFootprint() {
  for (let i = 0; i < footprints.length; i++) {
    fill(252, 233, 29);
    stroke(252, 233, 29);
    let footprintShape = footprints[i].shape;
    if (footprintShape === "circle") {
      fill(0, 153, 51)
      stroke(0, 153, 51)
      ellipse(footprints[i].x-70, footprints[i].y, 20, 20);
      fill(255, 255, 153);
      stroke(255, 255, 153);
      ellipse(footprints[i].x-78, footprints[i].y-30, 5, 5);
      ellipse(footprints[i].x-55, footprints[i].y+15, 7, 7);
    } else if (footprintShape === "diamond") {
    fill(252, 233, 29);
    stroke(252, 233, 29);
    beginShape();
    vertex(footprints[i].x -70, footprints[i].y - 20);
    vertex(footprints[i].x - 85, footprints[i].y );
    vertex(footprints[i].x -70 , footprints[i].y + 20);
    vertex(footprints[i].x - 55, footprints[i].y );
    endShape(CLOSE);
    } else if (footprintShape === "triangle") {
      fill(255);
      stroke(255);
      triangle(
        footprints[i].x-70,
        footprints[i].y - 12,
        footprints[i].x - 85,
        footprints[i].y + 18,
        footprints[i].x -55,
        footprints[i].y + 18
      );
    }
  }
  if(footprints.length === 0 || x - footprints[footprints.length - 1].x >= 20) {
    let newFootprintShape = random(["circle", "diamond", "triangle"]);
    footprints.push({ x: x, y: y, shape: newFootprintShape });
  }
}

function drawCircleTrail() {
  beginShape();
    for (let i = 0; i < circleTrail.length; i++) {
      let randomGreen = random(100, 255);
      fill(0, randomGreen, 0);
      stroke(0, randomGreen, 0);
      ellipse(circleTrail[i].x, circleTrail[i].y, 5, 5);
      ellipse(circleTrail[i].x, 500 - circleTrail[i].y, 5, 5);
    }
    endShape();
  for(let i =50;i<800;i+=210){
    fill(255,0,0);
    stroke(255,0,0);
    circle(i,113,5);
    circle(i,387,5);
    fill(255);
    stroke(255);
    circle(i+105,130,5);
    circle(i+105,370,5);
  }
}

