  translate(15, 25);
  rotate(-30 + sin(frameCount * 2.5 + 90) * 2);
  rect(0, 52, 20, 110, 10);
  translate(0, 95);
  rotate(-15);
  rect(0, 25, 18, 55, 8);

  // shoe
