let colors = []; // empty array
let selectedIndex = -1;
let angle = 0;
let x, y;
let dia;

function setup() {
    createCanvas(windowWidth, windowHeight * 0.85);
    angleMode(DEGREES);

    colors[0] = color(255, 105, 180); // pink;
    colors[1] = color(120, 81, 169); // purple
    colors[2] = color(64, 224, 208); // blue
    colors[3] = color(50, 205, 50); // green
    colors[4] = color(255, 255, 0); // yellow

    background(255);
}

function draw() {
    // COLOR PALETTES
    for (let i = 0; i < colors.length; i++) {
        let x = i * 30;
        let y = height - 30;
        noStroke();
        fill(colors[i]);
        rect(x, y, 30, 30);
    }

    x = sin(frameCount * 1.5) * 15; // freq, amp
    y = sin(frameCount * 1.0) * 50;
    angle += 60 + 0.1; // angle, 72, 60, 90, 120, ..

    push();
    translate(width / 2, height / 2);
    rotate(angle);

    if (mouseIsPressed && selectedIndex >= 0) {
        let c = colors[selectedIndex];
        fill(
            red(c) + random(-15, 15),
            green(c) + random(-15, 15),
            blue(c) + random(-15, 15)
        );
        if (selectedIndex == 0) {
            circle(x, y + 100, 25);
        } else if (selectedIndex == 1) {
            circle(x, y + 150, 10);
        } else if (selectedIndex == 2) {
            circle(x, y, 30);
        } else if (selectedIndex == 3) {
            circle(x, y + 50, 15);
        } else if (selectedIndex == 4) {
            circle(x, y + 200, 30);
        }
    }

    pop();
    //draw random-colored circles on background
    if (keyIsPressed) {
        if (key == "s") {
            noStroke();
            //stroke(random(255), random(255), random(255));
            fill(color(random(255), random(255), random(255), 70));
            circle(mouseX, mouseY, 100);
        }
    }

    //draw random-sized random-colored circles on background
    if (keyIsPressed) {
        if (key == "a") {
            fill(random(255), random(255), random(255), 90);
            circle(
                mouseX + random(-1, 1) * 50,
                mouseY + random(-1, 1) * 50,
                random(5, 100)
            );
        }
    }

    //white-out (erase)
    if (keyIsPressed) {
        if (key == "w") {
            noStroke();
            fill(255);
            circle(mouseX, mouseY, 50);
        }
    }

    //black-out (erase)
    if (keyIsPressed) {
        if (key == "q") {
            noStroke();
            fill(0);
            circle(mouseX, mouseY, 50);
        }
    }

    //console.log(frameRate());
}

