class Particle {
  constructor(x, y, rad) {
    this.x = x;
    this.y = y;
    this.xSpeed = 0;
    this.ySpeed = random(1, 3);
    this.rad = rad;
  }
  move() {
    //this.x += this.xSpeed;
    this.x += random(-2, 2);
    this.y += this.ySpeed;
  }
  reappear() {
    if (this.x < 0) {
      this.x = width;
    } else if (this.x > width) {
      this.x = 0;
    }
    if (this.y < 0) {
      this.y = height;
    } else if (this.y > height) {
      this.y = 0;
    }
  }
  display() {
    push();
    noStroke();
    fill(255, 150);
    circle(this.x, this.y, this.rad * 2);
    circle(this.x, this.y, this.rad * 1.5);
    circle(this.x, this.y, this.rad * 1.2);
    pop();
  }
}

