// from https://stackoverflow.com/a/9614122
function angleBetweenTwoPoints(cx, cy, ex, ey) {
  var dy = ey - cy;
  var dx = ex - cx;
  var theta = atan2(dy, dx); // range (-PI, PI]
  // theta *= 180 / PI; // rads to degs, range (-180, 180]
  if (theta < 0) theta = 2 * PI + theta; // range [0, 360)
  return theta;
}

